import{_ as e,c as l,o as i,a3 as o,aU as t}from"./chunks/framework.B1hip2RX.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"post/note/tools.md","filePath":"post/note/tools.md","lastUpdated":1716908736000}'),c={name:"post/note/tools.md"},d=o('<h2 id="_1-git" tabindex="-1">1. Git <a class="header-anchor" href="#_1-git" aria-label="Permalink to &quot;1. Git&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">git 日常基本操作</p><ul><li><code>git init</code>初始化仓库，默认为 master 分支</li><li><code>git add .</code>提交全部文件修改到缓存区</li><li><code>git add &lt;具体某个文件路径+全名&gt;</code>提交某些文件到缓存区</li><li><code>git diff</code>查看当前代码 add后，会 add 哪些内容</li><li><code>git diff --staged</code>查看现在 commit 提交后，会提交哪些内容</li><li><code>git status</code>查看当前分支状态</li><li><code>git pull &lt;远程仓库名&gt; &lt;远程分支名&gt;</code>拉取远程仓库的分支与本地当前分支合并</li><li><code>git pull &lt;远程仓库名&gt; &lt;远程分支名&gt;:&lt;本地分支名&gt;</code>拉取远程仓库的分支与本地某个分支合并</li><li><code>git commit -m &quot;&lt;注释&gt;&quot;</code>提交代码到本地仓库，并写提交注释</li><li><code>git commit -v</code>提交时显示所有diff信息</li><li><code>git commit --amend [file1] [file2]</code>重做上一次commit，并包括指定文件的新变化</li></ul></div><div class="tip custom-block"><p class="custom-block-title">关于提交信息的格式，可以遵循以下的规则</p><ul><li><code>feat</code>新特性，添加功能</li><li><code>fix</code>修改 bug</li><li><code>refactor</code>代码重构</li><li><code>docs</code>文档修改</li><li><code>style</code>代码格式修改, 注意不是 css 修改</li><li><code>test</code>测试用例修改</li><li><code>chore</code>其他修改, 比如构建流程, 依赖管理</li></ul></div><div class="tip custom-block"><p class="custom-block-title">分支操作</p><ul><li><code>git branch</code>查看本地所有分支</li><li><code>git branch -r</code>查看远程所有分支</li><li><code>git branch -a</code>查看本地和远程所有分支</li><li><code>git merge &lt;分支名&gt;</code>合并分支</li><li><code>git merge --abort</code>合并分支出现冲突时，取消合并，一切回到合并前的状态</li><li><code>git branch &lt;新分支名&gt;</code>基于当前分支，新建一个分支</li><li><code>git checkout --orphan &lt;新分支名&gt;</code>新建一个空分支（会保留之前分支的所有文件）</li><li><code>git branch -D &lt;分支名&gt;</code>删除本地某个分支</li><li><code>git push &lt;远程库名&gt; :&lt;分支名&gt;</code>删除远程某个分支</li><li><code>git branch &lt;新分支名称&gt; &lt;提交ID&gt;</code>从提交历史恢复某个删掉的某个分支</li><li><code>git branch -m &lt;原分支名&gt; &lt;新分支名&gt;</code>分支更名</li><li><code>git checkout &lt;分支名&gt;</code>切换到本地某个分支</li><li><code>git checkout &lt;远程库名&gt;/&lt;分支名&gt;</code>切换到线上某个分支 -<code> git checkout -b &lt;新分支名&gt;</code>把基于当前分支新建分支，并切换为这个分支</li></ul></div><div class="tip custom-block"><p class="custom-block-title">远程同步</p><ul><li><code>git fetch [remote]</code>下载远程仓库的所有变动</li><li><code>git remote -v</code>显示所有远程仓库</li><li><code>git pull [remote] [branch]</code>拉取远程仓库的分支与本地当前分支合并</li><li><code>git fetch</code>获取线上最新版信息记录，不合并</li><li><code>git push [remote] [branch]</code>上传本地指定分支到远程仓库</li><li><code>git push [remote] --force</code>强行推送当前分支到远程仓库，即使有冲突</li><li><code>git push [remote] --all</code>推送所有分支到远程仓库</li></ul></div><div class="tip custom-block"><p class="custom-block-title">撤销</p><ul><li><code>git checkout [file]</code>恢复暂存区的指定文件到工作区</li><li><code>git checkout [commit] [file]</code>恢复某个commit的指定文件到暂存区和工作区</li><li><code>git checkout .</code>恢复暂存区的所有文件到工作区</li><li><code>git reset [commit]</code>重置当前分支的指针为指定commit，同时重置暂存区，但工作区不变</li><li><code>git reset --hard</code>重置暂存区与工作区，与上一次commit保持一致</li><li><code>git reset [file]</code>重置暂存区的指定文件，与上一次commit保持一致，但工作区不变</li><li><code>git revert [commit]</code>后者的所有变化都将被前者抵消，并且应用到当前分支</li></ul></div><div class="tip custom-block"><p class="custom-block-title">存储操作</p><ul><li><code>git stash</code>暂时将未提交的变化移除</li><li><code>git stash pop</code>取出储藏中最后存入的工作状态进行恢复，会删除储藏</li><li><code>git stash list</code>查看所有储藏中的工作</li><li><code>git stash apply &lt;储藏的名称&gt;</code>取出储藏中对应的工作状态进行恢复，不会删除储藏</li><li><code>git stash clear</code>清空所有储藏中的工作</li><li><code>git stash drop &lt;储藏的名称&gt;</code>删除对应的某个储</li></ul></div><div class="warning custom-block"><p class="custom-block-title">token过期重新设置</p><ul><li><a href="https://github.com/settings/tokens" target="_blank" rel="noreferrer">创建一个令牌</a>: <code>Create personal access token</code></li><li>然后重置<code>Git</code>凭据: <code>git config --global --unset credential.helper</code></li><li>克隆或拉取您的存储库： <code>git push</code></li><li>然后输入令牌作为密码</li><li>保存你的令牌：<code>git config --global credential.helper store</code></li></ul></div><div class="tip custom-block"><p class="custom-block-title">总结</p><p><img src="'+t+'" alt="pic" title="notice"></p></div><h2 id="_2-n" tabindex="-1">2. N <a class="header-anchor" href="#_2-n" aria-label="Permalink to &quot;2. N&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">n</p><ul><li><code>npm install -g n</code>全局安装 n</li><li><code>sudo n</code>查看已安装node列表并切换</li><li><code>n ls</code>查看已安装node列表</li><li><code>n lsr</code>Displaying 20 matches (use --all to see all)</li><li><code>sudo n stable</code>安装稳定版本</li><li><code>sudo n latest</code>安装最新版本</li><li><code>sudo n 8.4.0</code>安装指定版本</li><li><code>sudo n rm 8.4.0</code>删除某个版本</li><li><code>n prune</code>删除除已安装版本外的所有缓存版本</li><li><code>n use 8.4.0 index.js</code>以指定的版本来执行脚本</li><li><code>sudo NODE_MIRROR=http://npm.taobao.org/mirrors/node n stable</code>更新阿里镜像解决超时问题</li></ul></div><h2 id="_3-homebrew" tabindex="-1">3. Homebrew <a class="header-anchor" href="#_3-homebrew" aria-label="Permalink to &quot;3. Homebrew&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">brew</p><ul><li><code>brew -v</code> 查询版本</li><li><code>brew -h</code> 查看帮助信息</li><li><code>brew update</code> 更新Homebrew</li><li><code>brew install &lt;pkg_name&gt;</code> 安装软件</li><li><code>brew uninstall &lt;pkg_name&gt;</code> 卸载软件</li><li><code>brew search &lt;pkg_name&gt;</code> 查询任意包</li><li><code>brew info &lt;pkg_name&gt;</code> 查看任意包内容信息</li><li><code>brew list</code> 列出已安装的软件列表</li><li><code>brew list git</code> 列出已安装软件git的文件目录</li><li><code>brew upgrade</code> 更新所有</li><li><code>brew upgrade &lt;pkg_name&gt;</code> 更新指定包</li><li><code>brew cleanup</code> 清理所有包的旧版本</li><li><code>brew cleanup &lt;pkg_name&gt;</code> 清理指定包的旧版本</li><li><code>brew outdated</code> 查询可更新的包</li><li><code>brew update &amp;&amp; brew upgrade &amp;&amp; brew cleanup</code> 更新软件版本-清理旧版本或已删除的软件</li></ul></div><h2 id="_4-vitepress" tabindex="-1">4. Vitepress <a class="header-anchor" href="#_4-vitepress" aria-label="Permalink to &quot;4. Vitepress&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">vitepress更新</p><ul><li>直接<code>npm install vitepress</code>升级到最新版本</li><li>需要在<code>main</code>分支上提交<code>vitepress</code>更新后的代码</li><li><code>gh-page</code>分支无需变动和之前一样提交</li><li>other(遇到npm install package 时，其实已经安装成功，但是进度还是显示安装中，重新设置npn源解决问题了) <ul><li>npm config get registry : <a href="https://registry.npmjs.org/" target="_blank" rel="noreferrer">https://registry.npmjs.org/</a></li><li>yarn config get registry : <a href="https://registry.npmjs.org/" target="_blank" rel="noreferrer">https://registry.npmjs.org/</a></li><li>npm config set registry <a href="https://registry.npm.taobao.org/" target="_blank" rel="noreferrer">https://registry.npm.taobao.org/</a></li><li>yarn config set registry <a href="https://registry.npm.taobao.org/" target="_blank" rel="noreferrer">https://registry.npm.taobao.org/</a></li></ul></li></ul></div><h2 id="_5-selenium" tabindex="-1">5. Selenium <a class="header-anchor" href="#_5-selenium" aria-label="Permalink to &quot;5. Selenium&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">元素定位</p><ul><li>id:<code>driver.findElement(By.id(&#39;kw&#39;))</code></li><li>name:<code>driver.findElement(By.name(&#39;wd&#39;))</code></li><li>class:<code>driver.findElement(By.className(&#39;s_ipt&#39;))</code></li><li>tag:<code>driver.findElement(By.tagName(&#39;input&#39;))</code></li><li>link-text:<code>driver.findElement(By.linkText(&#39;新闻&#39;))</code></li><li>partial-link-text:<code>driver.findElement(By.partialLinkText(&#39;新&#39;))</code></li><li>xpath: <ul><li>绝对路径：<code>driver.findElement(By.xpath(/html/body/div[2]/div[1]/div[5]/div/div/form/span[1]/input))</code></li><li>相对路径 <ul><li>相对路径+索引定位：<code>driver.findElement(By.xpath(&quot;//form/span[1]/input&quot;))</code></li><li>相对路径+属性定位：<code>driver.findElement(By.xpath(&quot;//input[@autocomplete=&#39;off]&quot;))</code></li><li>相对路径+通配符定位： <ul><li><code>driver.findElement(By.xpath(&quot;//*[@autocomplete=&#39;off&#39;]&quot;))</code></li><li><code>driver.findElement(By.xpath(&quot;//*[@*=&#39;off&#39;]&quot;))</code></li></ul></li><li>相对路径+部分属性值定位： <ul><li><code>driver.findElement(By.xpath(&quot;//*[starts-with(@autocomplete,&#39;of&#39;)]&quot;))</code></li><li><code>driver.findElement(By.xpath(&quot;//*[substring(@autocomplete,2)]=&#39;ff&#39;&quot;))</code></li><li><code>driver.findElement(By.xpath(&quot;//*[contains(@autocomplete,&#39;ff&#39;)]&quot;))</code></li></ul></li><li>相对路径+文本定位：<code>driver.findElement(By.xpath(&quot;//span[text()=&#39;按图片搜索&#39;]&quot;))</code></li></ul></li></ul></li><li>css: <ul><li>绝对路径：不用</li><li>通过Id和Class定位</li><li>通过属性定位</li><li>通过部分属性定位</li><li>查询子元素定位</li><li>查询兄弟节点定位</li></ul></li></ul></div><div class="warning custom-block"><p class="custom-block-title">元素操作</p><ul><li><code>click()</code>:点击元素</li><li><code>clear()</code>:清除元素内容</li><li><code>send_keys()</code>:模拟按键输入</li><li><code>get_attribute()</code>:获取元素的属性值</li><li><code>get_text()</code>:获取元素的文本内容</li><li><code>is_displayed()</code>:判断元素是否可见</li><li><code>is_enabled()</code>:判断元素是否可用</li><li><code>is_selected()</code>:判断元素是否被选中</li><li><code>get_location()</code>:获取元素的位置信息</li><li><code>get_size()</code>:获取元素的尺寸信息</li><li><code>get_cookies()</code>:获取所有Cookie信息</li><li><code>get_cookie()</code>:获取指定Cookie信息</li><li><code>delete_cookie()</code>:删除指定Cookie信息</li><li><code>delete_all_cookies()</code>:删除所有Cookie信息</li><li><code>execute_script()</code>:执行JavaScript脚本</li><li><code>execute_async_script()</code>:执行异步JavaScript脚本</li><li><code>get_screenshot_as_base64()</code>:获取当前页面的截图，并将其转换为Base64编码的字符串</li><li><code>get_screenshot_as_file()</code>:获取当前页面的截图，并将其保存到指定的文件路径中</li><li><code>refresh()</code>:刷新当前页面</li><li><code>back()</code>:后退到上一个页面</li><li><code>forward()</code>:前进到下一个页面</li><li><code>close()</code>:关闭当前页面</li><li><code>quit()</code>:关闭浏览器</li></ul></div><div class="info custom-block"><p class="custom-block-title">浏览器操作</p><ul><li><code>maximize_window()</code>:最大化浏览器窗口</li><li><code>minimize_window()</code>:最小化浏览器窗口</li><li><code>fullscreen_window()</code>:进入全屏模式</li><li><code>set_window_size()</code>:设置浏览器窗口的大小</li><li><code>get_window_size()</code>:获取浏览器窗口的大小</li><li><code>set_window_position()</code>:设置浏览器窗口的位置</li><li><code>get_window_position()</code>:获取浏览器窗口的位置</li><li><code>set_window_rect()</code>:设置浏览器窗口的位置和大小</li><li><code>get_window_rect()</code>:获取浏览器窗口的位置和大小</li></ul></div><div class="info custom-block"><p class="custom-block-title">Select方法</p><ul><li><code>select_by_index()</code>:通过索引选择选项</li><li><code>select_by_value()</code>:通过值选择选项</li><li><code>select_by_visible_text()</code>:通过可见文本选择选项</li><li><code>deselect_all()</code>:取消选择所有选项</li><li><code>deselect_by_index()</code>:取消选择指定索引的选项</li><li><code>deselect_by_value()</code>:取消选择指定值的选项</li><li><code>deselect_by_visible_text()</code>:取消选择指定可见文本的选项</li></ul></div><div class="info custom-block"><p class="custom-block-title">等待方法</p><ul><li><code>implicitly_wait()</code>:设置全局 implicit 等待时间</li><li><code>set_script_timeout()</code>:设置全局 script 等待时间</li><li><code>set_page_load_timeout()</code>:设置全局 page load 等待时间</li><li><code>set_implicit_wait()</code>:设置当前会话的 implicit 等待时间</li><li><code>set_script_timeout()</code>:设置当前会话的 script 等待时间</li><li><code>set_page_load_timeout()</code>:设置当前会话的 page load 等待时间</li></ul></div><div class="info custom-block"><p class="custom-block-title">异常处理</p><ul><li><code>ignore_exception()</code>:忽略指定异常</li><li><code>ignore_exceptions()</code>:忽略所有异常</li></ul></div><div class="info custom-block"><p class="custom-block-title">文件</p><ul><li><code>upload_file()</code>:上传文件到指定元素</li><li><code>download_file()</code>:下载指定文件到指定路径</li></ul></div><div class="info custom-block"><p class="custom-block-title">鼠标操作</p><ul><li><code>move_to_element()</code>:将鼠标移动到指定元素</li><li><code>move_to_element_with_offset()</code>:将鼠标移动到指定元素并偏移指定位置</li><li><code>click_and_hold()</code>:点击并保持指定元素</li><li><code>release()</code>:释放指定元素</li><li><code>double_click()</code>:双击指定元素</li><li><code>context_click()</code>:右击指定元素</li><li><code>drag_and_drop()</code>:拖拽指定元素</li><li><code>drag_and_drop_by_offset()</code>:拖拽指定元素并偏移指定位置</li></ul></div><div class="info custom-block"><p class="custom-block-title">键盘操作</p><ul><li><code>press_key()</code>:按下指定键</li><li><code>release_key()</code>:释放指定键</li><li><code>send_keys()</code>:模拟按键输入</li></ul></div><div class="info custom-block"><p class="custom-block-title">滚动操作</p><ul><li><code>scroll_to_element()</code>:滚动到指定元素</li><li><code>scroll_to_position()</code>:滚动到指定位置</li><li><code>scroll_by_offset()</code>:滚动指定偏移量</li></ul></div><div class="info custom-block"><p class="custom-block-title">在使用 Selenium 的 WebDriverWait 和 ExpectedConditions (EC) 时,常见的一些方法包括:</p><p>visibility_of_element_located(locator): 等待元素可见。 presence_of_element_located(locator): 等待元素存在于 DOM 中。 presence_of_all_elements_located(locator): 等待所有元素都存在于 DOM 中。 visibility_of_all_elements_located(locator): 等待所有元素都可见。 text_to_be_present_in_element(locator, text): 等待元素的文本包含指定的文本。 text_to_be_present_in_element_value(locator, text): 等待元素的 value 属性包含指定的文本。 title_contains(title): 等待页面标题包含指定的文本。 title_is(title): 等待页面标题等于指定的文本。 url_contains(url): 等待当前 URL 包含指定的 URL 片段。 url_matches(regex): 等待当前 URL 与指定的正则表达式匹配。 url_to_be(url): 等待当前 URL 等于指定的 URL。 alert_is_present(): 等待 alert 框出现。 element_to_be_clickable(locator): 等待元素可点击。 staleness_of(element): 等待指定元素从 DOM 中移除。 element_attribute_to_be(locator, attribute, value): 等待元素的属性值等于指定的值。 这些只是 ExpectedConditions 中的部分方法,实际上还有更多可供选择。选择合适的方法取决于您的具体测试场景和需求。</p></div>',27),s=[d];function a(r,n,u,p,m,_){return i(),l("div",null,s)}const h=e(c,[["render",a]]);export{b as __pageData,h as default};
